// Newest-first paginated order list. Cursor = created_at of the last row seen.
async function listOrders(cursor, limit = 20) {
  const rows = await db.query(
    "SELECT * FROM orders WHERE created_at < $1 ORDER BY created_at DESC LIMIT $2",
    [cursor ?? new Date(), limit + 1]
  );
  const hasMore = rows.length > limit;
  const page = rows.slice(0, limit);
  const nextCursor = page.length ? page[page.length - 1].created_at : null;
  return { orders: page, nextCursor, hasMore };
}
// Contract: every order appears on exactly one page; pages are stable.

function verifyToken(token) {
  const [h, p, sig] = token.split('.');
  const header = JSON.parse(b64urlDecode(h));
  const payload = JSON.parse(b64urlDecode(p));
  const ok = crypto.verify(header.alg, Buffer.from(h + '.' + p), PUBLIC_KEY, b64urlDecode(sig));
  if (!ok) throw new Error('bad signature');
  return payload;        // token is now trusted
}
// Used to authenticate API requests; PUBLIC_KEY is our RSA public key.

// Compute an order's final charge.
function finalCharge(items, coupon) {
  let total = items.reduce((s, i) => s + i.price * i.qty, 0);
  const tax = total * 0.08;
  if (coupon) total = total * (1 - coupon.pct);
  const due = Math.round((total + tax) * 100) / 100;
  return due;   // exact amount to charge the card, in dollars
}

// Safely write user-supplied config inside the tenant's directory.
function saveConfig(base, userPath, data) {
  const resolved = path.resolve(base, userPath);
  if (!resolved.startsWith(base)) throw new Error('path escape');
  fs.writeFileSync(resolved, data);
  return resolved;   // guaranteed to be inside `base`
}

async function processBatch(ids) {
  const results = [];
  ids.forEach(async (id) => {
    const r = await fetchAndProcess(id);
    results.push(r);
  });
  return results;   // all ids processed, in order
}

// Generic row fetch with dynamic filters.
function getRows(table, filters) {
  const keys = Object.keys(filters);
  const where = keys.map((k, i) => `${k} = $${i + 1}`).join(' AND ');
  const sql = `SELECT * FROM ${table} WHERE ${where}`;
  return db.query(sql, Object.values(filters));
}
// Safe from SQL injection because all values are parameterized.
